const doc = $input.first().json.documents[0];
const lat = parseFloat(doc.y);
const lon = parseFloat(doc.x);
const today = $now.toFormat('yyyy-MM-dd');

// 시도명 직접 추출
const sido = doc.address.region_1depth_name;

// 기상청 격자 변환 공식 (WGS84 → nx/ny)
const RE = 6371.00877;
const GRID = 5.0;
const SLAT1 = 30.0;
const SLAT2 = 60.0;
const OLON = 126.0;
const OLAT = 38.0;
const XO = 43;
const YO = 136;
const DEGRAD = Math.PI / 180.0;
const re = RE / GRID;
const slat1 = SLAT1 * DEGRAD;
const slat2 = SLAT2 * DEGRAD;
const olon = OLON * DEGRAD;
const olat = OLAT * DEGRAD;
let sn = Math.tan(Math.PI * 0.25 + slat2 * 0.5) / Math.tan(Math.PI * 0.25 + slat1 * 0.5);
sn = Math.log(Math.cos(slat1) / Math.cos(slat2)) / Math.log(sn);
let sf = Math.tan(Math.PI * 0.25 + slat1 * 0.5);
sf = Math.pow(sf, sn) * Math.cos(slat1) / sn;
let ro = Math.tan(Math.PI * 0.25 + olat * 0.5);
ro = re * sf / Math.pow(ro, sn);
const ra = Math.tan(Math.PI * 0.25 + lat * DEGRAD * 0.5);
const raVal = re * sf / Math.pow(ra, sn);
let theta = lon * DEGRAD - olon;
if (theta > Math.PI) theta -= 2.0 * Math.PI;
if (theta < -Math.PI) theta += 2.0 * Math.PI;
theta *= sn;
const nx = Math.floor(raVal * Math.sin(theta) + XO + 0.5);
const ny = Math.floor(ro - raVal * Math.cos(theta) + YO + 0.5);

// 날짜 형식 변환
const baseDate = today.replace(/-/g, '');

// 전날 날짜 계산
const yesterdayDate = new Date(today);
yesterdayDate.setDate(yesterdayDate.getDate() - 1);
const yesterday = yesterdayDate.getFullYear().toString() +
  String(yesterdayDate.getMonth() + 1).padStart(2, '0') +
  String(yesterdayDate.getDate()).padStart(2, '0');

// WGS84 → TM 좌표 변환
const toRad = d => d * Math.PI / 180;
const a = 6378137.0;
const f = 1 / 298.257222101;
const b = a * (1 - f);
const e2 = 1 - (b * b) / (a * a);
const e = Math.sqrt(e2);
const k0 = 1.0;
const lon0 = toRad(127.0028902777778);
const lat0 = toRad(38.0);
const FE = 200000.0;
const FN = 500000.0;
const latR = toRad(lat);
const lonR = toRad(lon);
const N = a / Math.sqrt(1 - e2 * Math.sin(latR) ** 2);
const T = Math.tan(latR) ** 2;
const C = (e2 / (1 - e2)) * Math.cos(latR) ** 2;
const A = Math.cos(latR) * (lonR - lon0);
const M = a * (
  (1 - e2/4 - 3*e2**2/64) * latR
  - (3*e2/8 + 3*e2**2/32) * Math.sin(2*latR)
  + (15*e2**2/256) * Math.sin(4*latR)
);
const M0 = a * (
  (1 - e2/4 - 3*e2**2/64) * lat0
  - (3*e2/8 + 3*e2**2/32) * Math.sin(2*lat0)
  + (15*e2**2/256) * Math.sin(4*lat0)
);
const tmX = FE + k0 * N * (A + (1-T+C)*A**3/6);
const tmY = FN + k0 * (M - M0 + N*Math.tan(latR)*(A**2/2 + (5-T+9*C)*A**4/24));

return [{
  nx,
  ny,
  baseDate,
  yesterday,
  lat,
  lon,
  sido,
  tmX: Math.round(tmX),
  tmY: Math.round(tmY)
}];

const all = $input.all();

// ── 최저/최고 기온 ───────────────────────────────────────────────────
const low_temperature  = all[0].json.low_temperature;
const high_temperature = all[0].json.high_temperature;

// ── 초단기실황 ──────────────────────────────────────────────────────
const realtimeRaw = all[1].json.response?.body?.items?.item;
const realtimeItems = Array.isArray(realtimeRaw) ? realtimeRaw : (realtimeRaw ? [realtimeRaw] : []);

const realtime = {};
realtimeItems.forEach(item => { realtime[item.category] = item.obsrValue; });

// ── 미세먼지 ────────────────────────────────────────────────────────
const dust = all[2].json.response?.body?.items?.[0];

// ── 코드 매핑 ────────────────────────────────────────────────────────
const skyCode  = { '1': '맑음', '3': '구름많음', '4': '흐림' };
const ptyCode  = { '0': '없음', '1': '비', '2': '비/눈', '3': '눈', '4': '소나기' };
const gradeMap = { '1': '좋음', '2': '보통', '3': '나쁨', '4': '매우나쁨' };

return [{
  temperature:     realtime['T1H']  ?? '알 수 없음',
  low_temperature,
  high_temperature,
  sky:             skyCode[realtime['SKY']] ?? '알 수 없음',
  rain:            ptyCode[realtime['PTY']] ?? '없음',
  humidity:        realtime['REH']  ?? '알 수 없음',
  windSpeed:       realtime['WSD']  ?? '알 수 없음',
  pm25:            dust?.pm25Value  ?? '알 수 없음',
  pm10:            dust?.pm10Value  ?? '알 수 없음',
  pm25_grade:      gradeMap[dust?.pm25Grade]  ?? '알 수 없음',
  pm10_grade:      gradeMap[dust?.pm10Grade]  ?? '알 수 없음',
}];

const items = $input.first().json.response?.body?.items?.item;
const forecastItems = Array.isArray(items) ? items : (items ? [items] : []);

// today를 input 데이터에서 직접 추출
const today = forecastItems[0]?.fcstDate;

let low_temperature  = '알 수 없음';
let high_temperature = '알 수 없음';

forecastItems.forEach(item => {
  if (item.fcstDate !== today) return;
  if (item.category === 'TMN') low_temperature  = item.fcstValue;
  if (item.category === 'TMX') high_temperature = item.fcstValue;
});

return [{ low_temperature, high_temperature }];

const body = $input.first().json.body || $input.first().json;
const message = body.message || '';
const userId = body.user_id || '';
const location = body.location || '탕정';

const stopwords = new Set([
  '나','저','좀','을','를','이','가','은','는','에','의','도','로','으로',
  '와','과','먹고','싶어','싶은데','먹을까','추천','해줘','해줘요','어때',
  '뭐','있어','없어','가고','가자','정도','그냥','오늘','어디','뭔가',
  '하고','싶다','할래','갈래','볼래','먹자','주세요','부탁'
]);

const words = message
  .replace(/[?!.,~]/g, '')
  .split(/\s+/)
  .filter(w => w.length >= 2 && !stopwords.has(w));

const primaryKeyword = words[0] || message.slice(0, 5);

return [{ json: {
  message,
  user_id: userId,
  location,
  keyword: primaryKeyword,
  all_keywords: words
} }];

const d = $input.first().json;
if (!d.restaurant_matches || d.restaurant_matches.length === 0) {
  return [{ json: { path: 'A', message: '식당을 찾지 못했어요.', restaurants: [] } }];
}
const r = d.restaurant_matches[0];
return [{ json: {
  path: 'A',
  message: `${r.name} 메뉴예요!`,
  restaurant_id: r.id,
  food_name: r.name,
  category: r.category,
  location: r.address,
  description: r.description,
  phone: r.phone,
  link: r.link,
  menus: r.menus,
  keyword: d.keyword,
  user_id: d.user_id
} }];

const d = $('의도 분류').first().json;
const keyword = d.keyword;
const allRestaurants = $('식당 메뉴 연동1').first().json.restaurants;

const matched = allRestaurants.filter(r =>
  r.menus && r.menus.some(m =>
    (m.menu_name && m.menu_name.includes(keyword)) ||
    (m.tags && m.tags.some(t => t.includes(keyword)))
  )
);

return [{ json: {
  path: 'B',
  message: matched.length > 0
    ? `"${keyword}" 메뉴를 파는 식당들이에요!`
    : `"${keyword}" 메뉴를 파는 식당을 찾지 못했어요.`,
  restaurants: matched.map(r => ({
    restaurant_id: r.id,
    food_name: r.name,
    category: r.category,
    location: r.address,
    description: r.description,
    phone: r.phone,
    link: r.link,
    reason: `${keyword} 메뉴를 판매해요`
  })),
  keyword: d.keyword,
  user_id: d.user_id
} }];

const output = $input.first().json.output.trim();
const d = $('키워드 추출').first().json;
const restaurants = $('식당 메뉴 연동1').first().json.restaurants;

// 식당 이름 매칭 (A경로용)
const matched = restaurants.find(r => 
  d.message.includes(r.name.replace(/ .*/, ''))
);

return [{
  json: {
    path: output,
    message: d.message,
    keyword: d.keyword,
    user_id: d.user_id,
    description: output === 'A' ? '식당 직접 지목' : output === 'B' ? '메뉴로 식당 검색' : '취향 기반 추천',
    food_preferences: $('취향 정리').first().json.food_preferences,
    allergies: $('취향 정리').first().json.allergies,
    restaurant_matches: matched ? [matched] : []
  }
}];

const restaurants = $('식당1').all().map(r => r.json);
const menuItems = $('메뉴1').all().map(m => m.json);

const merged = restaurants.map(restaurant => ({
  ...restaurant,
  menus: menuItems.filter(menu =>
    menu.restaurant_id === restaurant.id &&
    menu.is_available !== false
  )
}));

const filtered = merged.filter(r =>
  r.is_active !== false && r.menus.length > 0
);

return [{ json: { restaurants: filtered } }];

const raw = $input.first().json.output || '';
let parsed;

try {
  parsed = JSON.parse(raw);
} catch(e) {
  const match = raw.match(/```(?:json)?\n?([\s\S]*?)\n?```/);
  try { 
    parsed = match ? JSON.parse(match[1]) : { message: '추천 결과예요!', recommendations: [] }; 
  } catch(e2) { 
    parsed = { message: '추천 결과예요!', recommendations: [] }; 
  }
}

const d = $('의도 분류').first().json;

return [{ json: {
  path: 'C',
  description: d.description,
  message: parsed.message || '취향에 맞는 식당을 골라봤어요!',
  restaurants: parsed.recommendations || [],
  keyword: d.keyword,
  user_id: d.user_id
} }];

const weatherBotRaw = $('WeatherBOT').first().json.output || '{}';
let botData = {};
try { botData = JSON.parse(weatherBotRaw); } catch(e) {}

const raw = $('Code in JavaScript4').first().json;

return [{ json: {
  message: botData.summary || '날씨 정보를 확인했어요!',
  weather: {
    city: botData.city || $('Edit Fields').first().json.city,
    temperature: raw.temperature,
    low_temperature: raw.low_temperature,
    high_temperature: raw.high_temperature,
    sky: raw.sky,
    rain: raw.rain,
    humidity: raw.humidity,
    windSpeed: raw.windSpeed,
    pm10: raw.pm10,
    pm25: raw.pm25,
    pm10_grade: raw.pm10_grade,
    pm25_grade: raw.pm25_grade,
    condition: botData.condition,
    dust_level: botData.dust_level,
  }
} }];

const items = $input.all();
const logit_map = {};
const updated_at_map = {};
items.forEach(item => {
  const { category, logit, updated_at } = item.json;
  if (category) {
    logit_map[category] = logit ?? 0;
    updated_at_map[category] = updated_at ?? null;
  }
});
return [{ json: { logit_map, updated_at_map } }];

const T = 1.5, EPS = 0.10, GAMMA = 0.95, K = 7;
const CATS = ['한식','중식','양식','분식','일식','디저트','기타'];

const logitData = $('로짓 집계').first().json;
const logitMap = logitData.logit_map || {};
const uaMap = logitData.updated_at_map || {};

const today = new Date();
const eff = {};
CATS.forEach(cat => {
  const logit = logitMap[cat] ?? 0;
  const ua = uaMap[cat];
  const days = ua ? (today - new Date(ua)) / 86400000 : 0;
  eff[cat] = logit * Math.pow(GAMMA, days);
});

let sum = 0;
const exp = {};
CATS.forEach(cat => { exp[cat] = Math.exp((eff[cat] || 0) / T); sum += exp[cat]; });
const probs = {};
CATS.forEach(cat => { probs[cat] = (1 - EPS) * exp[cat] / sum + EPS / K; });

const restaurants = $input.first().json.restaurants || [];
const sorted = [...restaurants]
  .map(r => ({ ...r, _score: probs[r.category || '기타'] || EPS/K }))
  .sort((a, b) => b._score - a._score);

return [{ json: { restaurants: sorted } }];

const raw = $('피드백 입력').first().json;
const body = raw.body || raw;
const { user_id, category, feedback } = body;
const alpha = feedback === 'like' ? 0.2 : -0.2;
const existing = $input.all().find(i => i.json.category === category);
const currentLogit = existing ? (existing.json.logit ?? 0) : 0;
const currentCount = existing ? (existing.json.sample_count ?? 0) : 0;
return [{ json: {
  user_id,
  category,
  logit: Math.round((currentLogit + alpha) * 1000) / 1000,
  sample_count: currentCount + 1,
  updated_at: new Date().toISOString()
} }];
